\[
\begin{equation*}
n(u, v)=\frac{\partial S}{\partial u} \times \frac{\partial S}{\partial v} \tag{1}
\end{equation*}
\]

\[
\begin{equation*}
\mathcal{H}=\left\{\left(u_{0}, v_{0}\right) \mid\left\langle\left(L_{0}-L_{1}\right) \times n\left(u_{0}, v_{0}\right), L_{0}-S\left(u_{0}, v_{0}\right)\right\rangle=0\right\}, \tag{2}
\end{equation*}
\]

\[
\begin{equation*}
\cos (\theta)=\frac{\langle\mathbf{V}, n(u, v)\rangle}{\|n(u, v)\|} \tag{3}
\end{equation*}
\]

\[
\begin{equation*}
\cos ^{2}(\theta)\langle n(u, v), n(u, v)\rangle=\langle\mathbf{V}, n(u, v)\rangle^{2} \tag{4}
\end{equation*}
\]

\[
\begin{equation*}
\mathcal{F}_{i}(u, v)=\cos ^{2}(\theta)\langle n(u, v), n(u, v)\rangle-\langle\mathbf{V}, n(u, v)\rangle^{2}=0 . \tag{5}
\end{equation*}
\]

\[
\begin{equation*}
r(u, v)=2 n(u, v)-\mathbf{V} \frac{\langle n(u, v), n(u, v)\rangle}{\langle n(u, v), \mathbf{V}\rangle} . \tag{6}
\end{equation*}
\]

\[
\begin{equation*}
\mathbf{r}(u, v)=2 n(u, v)\langle n(u, v), \mathbf{V}\rangle-\mathbf{V}\langle n(u, v), n(u, v)\rangle, \tag{7}
\end{equation*}
\]

\[
\begin{equation*}
\left\langle S(u, v)-P_{l}, \mathbf{v}_{l} \times \mathbf{r}(u, v)\right\rangle=0, \tag{8}
\end{equation*}
\]

\[
\begin{equation*}
\left\langle S(u, v), \mathbf{v}_{l} \times \mathbf{r}(u, v)\right\rangle=\left\langle P_{l}, \mathbf{v}_{l} \times \mathbf{r}(u, v)\right\rangle \tag{9}
\end{equation*}
\]

\[
\begin{equation*}
\mathcal{F}_{r_{l}}(u, v)=\left\langle S(u, v), \mathbf{v}_{l} \times \mathbf{r}(u, v)\right\rangle-\left\langle P_{l}, \mathbf{v}_{l} \times \mathbf{r}(u, v)\right\rangle=0 . \tag{10}
\end{equation*}
\]

\[
\begin{equation*}
\cos (\alpha)=\frac{\left\langle P_{\mathcal{S}}-S(u, v), \mathbf{r}(u, v)\right\rangle}{\left\|P_{\mathcal{S}}-S(u, v)\right\|\|\mathbf{r}(u, v)\|} \tag{11}
\end{equation*}
\]

\[
\begin{equation*}
\cos ^{2}(\alpha)=\frac{\left\langle P_{\mathcal{S}}-S(u, v), \mathbf{r}(u, v)\right\rangle^{2}}{\left\langle P_{\mathcal{S}}-S(u, v), P_{\mathcal{S}}-S(u, v)\right\rangle\langle\mathbf{r}(u, v), \mathbf{r}(u, v)\rangle} \tag{12}
\end{equation*}
\]

\[
\begin{equation*}
\mathcal{F}_{r_{o}}(u, v)=\cos ^{2}(\alpha)-\frac{\left\langle P_{\mathcal{S}}-S(u, v), \mathbf{r}(u, v)\right\rangle^{2}}{\left\langle P_{\mathcal{S}}-S(u, v), P_{\mathcal{S}}-S(u, v)\right\rangle\langle\mathbf{r}(u, v), \mathbf{r}(u, v)\rangle}=0 . \tag{13}
\end{equation*}
\]

